function route(){ return (location.hash.replace(/^#\/?/, '') || 'home').replace(/^\//,''); }
function go(r){ location.hash = '/' + r; }
function escapeHTML(s=''){ return String(s).replace(/[&<>"']/g, m=>({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#039;' }[m])); }
function pageHero(title,kicker,text,img=ASSETS.hero){
  return `<section class="page-hero" style="--hero-img:url('${img}')"><div class="page-hero-inner"><nav class="breadcrumbs"><a href="#/home">Home</a><span>›</span><span>${title}</span></nav><span class="eyebrow">${kicker}</span><h1>${title}</h1><p>${text}</p></div></section>`;
}
function buttonLink(label, href, cls='btn btn-primary'){
  const ext = href && (href.startsWith('http') || href.startsWith('mailto:'));
  return `<a class="${cls}" href="${href}" ${ext?'target="_blank" rel="noopener"':''}>${label}</a>`;
}

