function quickAccess(){
  const items = [
    ['Admissions','Apply, prospectus, merit lists','admissions','A'],['Academics','Courses, departments, syllabi','academics','C'],['Notices','Admissions, exams, vacancies','notices','N'],['Exams','Results and revaluation links','exams','E'],['Downloads','Forms and PDFs','downloads','D'],['Faculty','Teaching and staff directory','faculty','F'],['Support','Counselling and scholarships','support','S'],['Contact','Office, phone and email','contact','☎']
  ];
  return `<section class="quick-wrap container"><div class="quick-grid">${items.map(i=>`<a class="quick-card reveal" href="#/${i[2]}"><span>${i[3]}</span><strong>${i[0]}</strong><small>${i[1]}</small></a>`).join('')}</div></section>`;
}
