function noticeRow(n){
  const href=linkFor(n), ext=href.startsWith('http') || n.file;
  return `<a class="notice-row reveal" href="${href}" ${ext?'target="_blank" rel="noopener"':''}><span class="date"><b>${new Date(n.date).toLocaleDateString('en-IN',{day:'2-digit',month:'short'})}</b><small>${new Date(n.date).getFullYear()}</small></span><span><strong>${n.title}</strong><small>${n.category} · ${n.summary}</small></span></a>`;
}
