function renderNotices(){
  main.innerHTML = `<div class="page">${pageHero('Notices','Updates','Admissions, exams, results, scholarships, vacancies, research and general notices.',ASSETS.event)}<section class="section container"><div class="filter-panel reveal" id="noticeFilters"></div><div class="notice-list page-list" id="noticeList"></div></section></div>`; afterRender(); setupNoticeFilters();
}
function setupNoticeFilters(){
  const cats=['All',...Array.from(new Set(DATA.notices.map(n=>n.category)))];
  const wrap=document.querySelector('#noticeFilters'); const list=document.querySelector('#noticeList');
  if(!wrap||!list) return;
  function draw(cat='All'){
    wrap.innerHTML=cats.map(c=>`<button class="filter ${c===cat?'active':''}" data-cat="${c}">${c}</button>`).join('');
    const arr=DATA.notices.filter(n=>cat==='All'||n.category===cat);
    list.innerHTML=arr.map(n=>`<article class="notice-card reveal"><div class="date"><b>${new Date(n.date).toLocaleDateString('en-IN',{day:'2-digit',month:'short'})}</b><small>${new Date(n.date).getFullYear()}</small></div><div><span class="eyebrow">${n.category}</span><h3>${n.title}</h3><p>${n.summary}</p></div><a class="pill gold" href="${linkFor(n)}" ${(n.external||n.file)?'target="_blank" rel="noopener"':''}>Open</a></article>`).join('');
    wrap.querySelectorAll('button').forEach(b=>b.onclick=()=>draw(b.dataset.cat)); revealNow();
  } draw();
}

