function renderFaculty(){
  main.innerHTML=`<div class="page">${pageHero('Staff Directory','People','Teaching staff, administrative staff, library staff, technical staff and support staff.',ASSETS.students)}<section class="section container"><div class="directory-controls reveal"><input id="facultySearch" type="search" placeholder="Search name, department or designation"><select id="facultyDept"><option value="All">All departments</option>${Array.from(new Set(DATA.faculty.map(f=>f.department))).sort().map(d=>`<option>${d}</option>`).join('')}</select><select id="facultyType"><option value="All">Teaching and Non-Teaching</option><option>Teaching</option><option>Non-Teaching</option></select></div><div class="faculty-grid" id="facultyGrid"></div></section></div>`; afterRender(); setupFaculty();
}
function setupFaculty(){
  const q=document.querySelector('#facultySearch'), d=document.querySelector('#facultyDept'), t=document.querySelector('#facultyType'), grid=document.querySelector('#facultyGrid');
  if(!grid) return;
  function draw(){
    const term=(q.value||'').toLowerCase(); const dept=d.value; const type=t.value;
    const arr=DATA.faculty.filter(f=>(dept==='All'||f.department===dept)&&(type==='All'||f.type===type)&&[f.name,f.department,f.role,f.email].join(' ').toLowerCase().includes(term));
    grid.innerHTML=arr.map(f=>`<article class="faculty-card reveal"><div class="avatar">${f.name.split(' ').map(x=>x[0]).slice(0,2).join('')}</div><div><span class="eyebrow">${f.department}</span><h3>${f.name}</h3><p>${f.role}</p><small>${f.phone}</small>${f.email?`<a href="mailto:${f.email}">${f.email}</a>`:''}</div></article>`).join(''); revealNow();
  }
  [q,d,t].forEach(el=>el.addEventListener('input',draw)); draw();
}
