  main.innerHTML=`<div class="page">${pageHero('Research & Publications','Academic Output','ANCHOR journal, calls for research papers, happenings, seminars, conferences and publication resources.',ASSETS.library)}<section class="section container"><div class="grid-3">${infoCard('ANCHOR Journal','Fr. Agnel College journals are available for students, faculty and researchers.')}${infoCard('Research Papers','Students and faculty can refer to the appeal and guidelines for publication in ANCHOR.')}${infoCard('Happenings','College activities and academic life are recorded through the Happenings publications.')}</div></section><section class="section container"><div class="download-grid">${pubs.map(downloadCard).join('')}</div></section></div>`; afterRender();
